/** Client-side auth: token storage, login, logout. */

import { fetchWithRetry } from './http';

const TOKEN_KEY = 'taskhub.token';

export function storeToken(token: string): void {
  window.localStorage.setItem(TOKEN_KEY, token);
}

export function getToken(): string | null {
  return window.localStorage.getItem(TOKEN_KEY);
}

export function clearToken(): void {
  window.localStorage.removeItem(TOKEN_KEY);
}

export async function login(email: string, password: string): Promise<void> {
  const result = await fetchWithRetry<{ token: string }>('/api/login', {
    method: 'POST',
    body: JSON.stringify({ email, password }),
  });
  storeToken(result.token);
}

"""Tiny in-memory TTL cache used for hot lookups (e.g. users by id)."""

import time
from typing import Any, Callable


class MemoCache:
    """Dict-backed cache with per-entry expiry. Not thread-safe."""

    def __init__(self, ttl_seconds: float = 60.0, clock: Callable[[], float] = time.monotonic) -> None:
        self.ttl = ttl_seconds
        self._clock = clock
        self._entries: dict[Any, tuple[float, Any]] = {}

    def get(self, key: Any) -> Any | None:
        entry = self._entries.get(key)
        if entry is None:
            return None
        expires_at, value = entry
        if self._clock() >= expires_at:
            del self._entries[key]
            return None
        return value

    def put(self, key: Any, value: Any) -> None:
        self._entries[key] = (self._clock() + self.ttl, value)

    def clear(self) -> None:
        self._entries.clear()

